**Apollo Server** (most popular):

**Install**:
```bash
npm install @apollo/server graphql
```

**Setup** (`server.js`):
```javascript
import { ApolloServer } from '@apollo/server';
import { startStandaloneServer } from '@apollo/server/standalone';

// Schema definition (type definitions)
const typeDefs = `#graphql
  type User {
    id: ID!
    name: String
    email: String
    posts: [Post]
  }

  type Post {
    id: ID!
    title: String
    content: String
    author: User
  }

  type Query {
    user(id: ID!): User
    users: [User]
    post(id: ID!): Post
  }

  type Mutation {
    createUser(name: String!, email: String!): User
    createPost(title: String!, content: String!, authorId: ID!): Post
  }
`;

// Resolvers (how to get data)
const resolvers = {
  Query: {
    user: async (_, { id }, { dataSources }) => {
      return dataSources.db.getUser(id);
    },
    users: async (_, __, { dataSources }) => {
      return dataSources.db.getUsers();
    },
    post: async (_, { id }, { dataSources }) => {
      return dataSources.db.getPost(id);
    }
  },

  Mutation: {
    createUser: async (_, { name, email }, { dataSources }) => {
      return dataSources.db.createUser({ name, email });
    },
    createPost: async (_, { title, content, authorId }, { dataSources }) => {
      return dataSources.db.createPost({ title, content, authorId });
    }
  },

  // Field resolvers (resolve relationships)
  User: {
    posts: async (parent, _, { dataSources }) => {
      return dataSources.db.getPostsByUserId(parent.id);
    }
  },

  Post: {
    author: async (parent, _, { dataSources }) => {
      return dataSources.db.getUser(parent.authorId);
    }
  }
};

// Start server
const server = new ApolloServer({ typeDefs, resolvers });
const { url } = await startStandaloneServer(server, {
  context: async () => ({
    dataSources: {
      db: yourDatabaseAPI
    }
  }),
  listen: { port: 4000 }
});

console.log(`GraphQL server ready at ${url}`);
```

