**Token bucket algorithm** with Redis:

```javascript
const redis = require('redis');
const client = redis.createClient();

async function rateLimit(userId, limit = 100, windowSeconds = 60) {
    const key = `ratelimit:${userId}`;
    const now = Math.floor(Date.now() / 1000);
    const windowStart = now - windowSeconds;

    // Lua script for atomic operation
    const luaScript = `
        local key = KEYS[1]
        local limit = tonumber(ARGV[1])
        local now = tonumber(ARGV[2])
        local windowStart = tonumber(ARGV[3])

        -- Remove old entries
        redis.call('ZREMRANGEBYSCORE', key, 0, windowStart)

        -- Count current requests
        local current = redis.call('ZCARD', key)

        if current < limit then
            -- Add current request
            redis.call('ZADD', key, now, now .. ':' .. math.random())
            redis.call('EXPIRE', key, ARGV[4])
            return {1, limit - current - 1}
        else
            return {0, 0}
        end
    `;

    const result = await client.eval(luaScript, {
        keys: [key],
        arguments: [limit, now, windowStart, windowSeconds]
    });

    return {
        allowed: result[0] === 1,
        remaining: result[1]
    };
}
```

**Simpler sliding window** (fixed window counter):
```javascript
async function slidingWindow(userId, limit = 100, windowSeconds = 60) {
    const key = `ratelimit:${userId}:${Math.floor(Date.now() / 1000 / windowSeconds)}`;

    const current = await client.incr(key);
    if (current === 1) {
        await client.expire(key, windowSeconds);
    }

    return {
        allowed: current <= limit,
        remaining: Math.max(0, limit - current)
    };
}
```

**Express middleware**:
```javascript
const rateLimitMiddleware = (limit, windowSeconds) => {
    return async (req, res, next) => {
        const userId = req.user?.id || req.ip;
        const result = await rateLimit(userId, limit, windowSeconds);

        // Set headers
        res.setHeader('X-RateLimit-Limit', limit);
        res.setHeader('X-RateLimit-Remaining', result.remaining);
        res.setHeader('X-RateLimit-Reset', Math.floor(Date.now() / 1000) + windowSeconds);

        if (result.allowed) {
            next();
        } else {
            res.status(429).json({ error: 'Too many requests' });
        }
    };
};

// Use
app.use('/api/', rateLimitMiddleware(100, 60));
app.use('/api/login', rateLimitMiddleware(5, 300)); // Stricter for auth
```

**Distributed** (across servers): Redis ensures global limit

**Advanced**: 
- **Bucket per endpoint + user**: `key = ratelimit:${endpoint}:${userId}`
- **Graceful burst**: Token bucket with capacity = 2x rate
- **Queuing**: Redis list + background processing

