Best practice: Catch specific exceptions first (bottom-up hierarchy). Avoid bare `except:` (catches KeyboardInterrupt, SystemExit). Use `except Exception` as catch-all for expected errors, then re-raise if unknown.

```python
class Node:
    def __init__(self, key):
        self.key = key
        self.left = None
        self.right = None

class BST:
    def __init__(self):
        self.root = None

    def insert(self, key):
        if not self.root:
            self.root = Node(key)
        else:
            self._insert(self.root, key)

    def _insert(self, node, key):
        if key < node.key:
            if node.left:
                self._insert(node.left, key)
            else:
                node.left = Node(key)
        elif key > node.key:
            if node.right:
                self._insert(node.right, key)
            else:
                node.right = Node(key)

    def search(self, key):
        return self._search(self.root, key)

    def _search(self, node, key):
        if not node or node.key == key:
            return node
        if key < node.key:
            return self._search(node.left, key)
        return self._search(node.right, key)

    def inorder(self):
        result = []
        self._inorder(self.root, result)
        return result

    def _inorder(self, node, result):
        if node:
            self._inorder(node.left, result)
            result.append(node.key)
            self._inorder(node.right, result)
```
Operations: O(log n) average, O(n) worst-case if unbalanced. Use `bisect` for sorted lists or `blist` if needed.

```python
from collections import OrderedDict

class LRUCache:
    def __init__(self, capacity):
        self.cache = OrderedDict()
        self.capacity = capacity

    def get(self, key):
        if key not in self.cache:
            return -1
        self.cache.move_to_end(key)
        return self.cache[key]

    def put(self, key, value):
        if key in self.cache:
            self.cache.move_to_end(key)
        self.cache[key] = value
        if len(self.cache) > self.capacity:
            self.cache.popitem(last=False)

# Using functools (built-in)
from functools import lru_cache

@lru_cache(maxsize=128)
def fib(n):
    if n < 2:
        return n
    return fib(n-1) + fib(n-2)
```

Manual doubly linked list + dict for O(1) operations (avoid OrderedDict overhead). Use `@lru_cache` for functions, custom class for more control.

**Saga Pattern**: Distributed transaction across microservices using compensating transactions.

**Two approaches**:

**1) Choreography** (event-driven):
```python
# Order Service
class OrderSaga:
    def create_order(self, order_id):
        # Step 1: Create order (pending)
        self.order_repo.save(order_id, 'PENDING')
        # Publish event
        event_bus.publish('OrderCreated', {'order_id': order_id})

    def on_payment_processed(self, event):
        if event['status'] == 'SUCCESS':
            self.order_repo.update(event['order_id'], 'CONFIRMED')
            event_bus.publish('OrderConfirmed', event)
        else:
            self.compensate(event['order_id'])

    def compensate(self, order_id):
        self.order_repo.update(order_id, 'CANCELLED')
        event_bus.publish('OrderCancelled', {'order_id': order_id})

# Payment Service
class PaymentSaga:
    def on_order_created(self, event):
        try:
            payment = self.payment_gateway.charge(event['order_id'])
            event_bus.publish('PaymentProcessed', {
                'order_id': event['order_id'],
                'status': 'SUCCESS',
                'payment_id': payment.id
            })
        except Exception:
            event_bus.publish('PaymentProcessed', {
                'order_id': event['order_id'],
                'status': 'FAILED'
            })
```

**2) Orchestration** (central coordinator):
```python
class SagaOrchestrator:
    def create_order_saga(self, order_details):
        saga_id = str(uuid4())
        self.state[saga_id] = {'step': 'ORDER_CREATED'}

        try:
            # Step 1: Create order
            order = order_service.create(order_details)
            self.state[saga_id]['order_id'] = order.id

            # Step 2: Process payment
            payment = payment_service.charge(order.id, order.total)
            self.state[saga_id]['payment_id'] = payment.id

            # Step 3: Reserve inventory
            inventory_service.reserve(order.id, order.items)

            # Success
            order_service.confirm(order.id)
            return {'saga_id': saga_id, 'status': 'SUCCESS'}

        except Exception as e:
            # Compensate (reverse order)
            if 'payment_id' in self.state[saga_id]:
                payment_service.refund(self.state[saga_id]['payment_id'])
            if 'order_id' in self.state[saga_id]:
                order_service.cancel(self.state[saga_id]['order_id'])
            return {'saga_id': saga_id, 'status': 'FAILED', 'error': str(e)}
```

**Compensation actions**:
- Create order → Cancel order
- Charge payment → Refund payment
- Reserve inventory → Release inventory
- Send email → No compensation (send apology email)

**Idempotency**: Use idempotency keys for all operations. Log all saga steps for recovery.

**CRDT**: Data structure that resolves conflicts automatically without central coordination. Merges always produce same result (convergent).

**Types**:

**1) State-based (CvRDT)**: Merge full state:
```python
class GCounter:  # Grow-only counter (only increments)
    def __init__(self):
        self.counts = {}  # replica_id -> count

    def inc(self, replica_id):
        self.counts[replica_id] = self.counts.get(replica_id, 0) + 1

    def value(self):
        return sum(self.counts.values())

    def merge(self, other):
        for replica, count in other.counts.items():
            self.counts[replica] = max(self.counts.get(replica, 0), count)
```

**2) Operation-based (CmRDT)**: Broadcast operations, need exactly-once delivery.

**Common CRDTs**:
- **GCounter**: Increment-only counter
- **PNCounter**: Increment/decrement (two GCounter: inc + dec)
- **GSet**: Add-only set
- **ORSet** (Observed-Remove Set): Add and remove (tombstones)
- **LWWRegister** (Last-Write-Wins): Store single value with timestamp

**Example ORSet**:
```python
class ORSet:
    def __init__(self):
        self.elements = {}  # element -> set of tags (ids)

    def add(self, element, tag):
        if element not in self.elements:
            self.elements[element] = set()
        self.elements[element].add(tag)

    def remove(self, element, tag):
        if element in self.elements:
            self.elements[element].discard(tag)

    def value(self):
        return [elem for elem, tags in self.elements.items() if tags]

    def merge(self, other):
        for elem, tags in other.elements.items():
            if elem not in self.elements:
                self.elements[elem] = set()
            self.elements[elem].update(tags)
```

**Use**: Real-time collaborative editing (Google Docs), distributed databases (Redis, Riak), offline-first apps.

**Advantages**: No coordination, low latency, peer-to-peer.
**Disadvantages**: Tombstones (memory growth), complex for some types (list CRDTs like RGA).

