```go
package main

import (
    "fmt"
    "log"
    "net/http"
    "github.com/gorilla/websocket"
)

var upgrader = websocket.Upgrader{
    CheckOrigin: func(r *http.Request) bool { return true },
}

// Client represents a single connected user
type Client struct {
    conn *websocket.Conn
    send chan []byte
    room *Room
    name string
}

// Room manages all clients in a chat room
type Room struct {
    clients    map[*Client]bool
    broadcast  chan []byte
    register   chan *Client
    unregister chan *Client
}

func NewRoom() *Room {
    return &Room{
        clients:    make(map[*Client]bool),
        broadcast:  make(chan []byte),
        register:   make(chan *Client),
        unregister: make(chan *Client),
    }
}

func (r *Room) Run() {
    for {
        select {
        case client := <-r.register:
            r.clients[client] = true
            log.Printf("Client %s joined, total: %d", client.name, len(r.clients))

        case client := <-r.unregister:
            if _, ok := r.clients[client]; ok {
                delete(r.clients, client)
                close(client.send)
                log.Printf("Client %s left, total: %d", client.name, len(r.clients))
            }

        case message := <-r.broadcast:
            for client := range r.clients {
                select {
                case client.send <- message:
                default:
                    close(client.send)
                    delete(r.clients, client)
                }
            }
        }
    }
}

func (c *Client) ReadPump() {
    defer func() {
        c.room.unregister <- c
        c.conn.Close()
    }()

    for {
        _, msg, err := c.conn.ReadMessage()
        if err != nil {
            break
        }
        // Format with sender name
        formatted := fmt.Sprintf("%s: %s", c.name, string(msg))
        c.room.broadcast <- []byte(formatted)
    }
}

func (c *Client) WritePump() {
    for msg := range c.send {
        err := c.conn.WriteMessage(websocket.TextMessage, msg)
        if err != nil {
            break
        }
    }
}

func serveWs(room *Room, w http.ResponseWriter, r *http.Request) {
    conn, err := upgrader.Upgrade(w, r, nil)
    if err != nil {
        log.Println(err)
        return
    }

    name := r.URL.Query().Get("name")
    if name == "" {
        name = "Anonymous"
    }

    client := &Client{
        conn: conn,
        send: make(chan []byte, 256),
        room: room,
        name: name,
    }

    room.register <- client

    go client.WritePump()
    go client.ReadPump()
}

func main() {
    room := NewRoom()
    go room.Run()

    http.HandleFunc("/ws", func(w http.ResponseWriter, r *http.Request) {
        serveWs(room, w, r)
    })
    http.HandleFunc("/", func(w http.ResponseWriter, r *http.Request) {
        http.ServeFile(w, r, "index.html")
    })

    log.Fatal(http.ListenAndServe(":8080", nil))
}
```

