import redis

class RedisLeaderElection:
    def __init__(self, redis_client, lock_key, ttl=30):
        self.redis = redis_client
        self.lock_key = lock_key
        self.ttl = ttl

    def try_acquire(self, node_id):
        # SET NX EX (atomic)
        acquired = self.redis.set(self.lock_key, node_id, nx=True, ex=self.ttl)
        return acquired

    def renew(self, node_id):
        # Extend only if still leader
        if self.redis.get(self.lock_key) == node_id:
            self.redis.expire(self.lock_key, self.ttl)
            return True
        return False

    def run_leader_loop(self, node_id, callback):
        while True:
            if self.try_acquire(node_id):
                print(f"Node {node_id} is leader")
                callback()
                # Renew periodically
                while self.renew(node_id):
                    time.sleep(self.ttl / 3)
                print(f"Node {node_id} lost leadership")
            else:
                time.sleep(5)  # Wait before retry
```

