**Bloom Filter**: Space-efficient probabilistic set membership.

```python
import mmh3  # murmurhash3
from bitarray import bitarray
import math

class BloomFilter:
    def __init__(self, expected_elements, false_positive_rate=0.01):
        self.size = self._calculate_size(expected_elements, false_positive_rate)
        self.hash_count = self._calculate_hash_count(self.size, expected_elements)
        self.bit_array = bitarray(self.size)
        self.bit_array.setall(0)

    def _calculate_size(self, n, p):
        # m = -n*ln(p) / (ln(2))^2
        m = -(n * math.log(p)) / (math.log(2) ** 2)
        return int(m)

    def _calculate_hash_count(self, m, n):
        # k = (m/n) * ln(2)
        k = (m / n) * math.log(2)
        return int(k)

    def _hashes(self, item):
        # Use double hashing to simulate k independent hashes
        hash1 = mmh3.hash(item, seed=0)
        hash2 = mmh3.hash(item, seed=1)
        for i in range(self.hash_count):
            yield (hash1 + i * hash2) % self.size

    def add(self, item):
        for hash_val in self._hashes(item):
            self.bit_array[hash_val] = 1

    def contains(self, item):
        for hash_val in self._hashes(item):
            if not self.bit_array[hash_val]:
                return False
        return True  # May be false positive

# Usage
bf = BloomFilter(expected_elements=100000, false_positive_rate=0.01)

# Add some URLs
bf.add("https://example.com")
bf.add("https://google.com")

# Check
print(bf.contains("https://example.com"))  # True
print(bf.contains("https://yahoo.com"))    # Probably False

# Cannot delete (unless counting bloom filter)
```

**Counting Bloom Filter** (supports delete):
```python
from array import array

class CountingBloomFilter:
    def __init__(self, expected_elements, false_positive_rate=0.01):
        self.size = self._calculate_size(expected_elements, false_positive_rate)
        self.hash_count = self._calculate_hash_count(self.size, expected_elements)
        self.counter = array('I', [0]) * self.size  # Unsigned int

    def add(self, item):
        for hash_val in self._hashes(item):
            self.counter[hash_val] += 1

    def delete(self, item):
        for hash_val in self._hashes(item):
            if self.counter[hash_val] > 0:
                self.counter[hash_val] -= 1

    def contains(self, item):
        for hash_val in self._hashes(item):
            if self.counter[hash_val] == 0:
                return False
        return True
