**Scalable Bloom Filter** (grows):
```python
class ScalableBloomFilter:
    def __init__(self, initial_capacity=100000, error_rate=0.01):
        self.filters = []
        self.current = BloomFilter(initial_capacity, error_rate)
        self.filters.append(self.current)
        self.error_rate = error_rate

    def add(self, item):
        if self.current.contains(item):
            return

        # Check if filter is full (estimate)
        if self.current.size * 0.9 < self.current.bit_array.count():
            # Create new, larger filter with tighter error rate
            new_capacity = len(self.filters) * 2 * 100000
            self.current = BloomFilter(new_capacity, self.error_rate / len(self.filters))
            self.filters.append(self.current)

        self.current.add(item)

    def contains(self, item):
        for bf in reversed(self.filters):  # Check newest first
            if bf.contains(item):
                return True
        return False
```

**Use cases**:
