**Union-Find** with path compression and union by rank:

```python
class UnionFind:
    def __init__(self, n):
        self.parent = list(range(n))
        self.rank = [0] * n
        self.components = n

    def find(self, x):
        """Find with path compression"""
        if self.parent[x] != x:
            self.parent[x] = self.find(self.parent[x])
        return self.parent[x]

    def union(self, x, y):
        """Union by rank"""
        root_x = self.find(x)
        root_y = self.find(y)

        if root_x == root_y:
            return False

        # Union by rank: attach smaller tree under larger
        if self.rank[root_x] < self.rank[root_y]:
            self.parent[root_x] = root_y
        elif self.rank[root_x] > self.rank[root_y]:
            self.parent[root_y] = root_x
        else:
            self.parent[root_y] = root_x
            self.rank[root_x] += 1

        self.components -= 1
        return True

    def connected(self, x, y):
        return self.find(x) == self.find(y)

    def count(self):
        return self.components

# Applications

# 1) Number of islands (2D grid)
def num_islands(grid):
    if not grid:
        return 0
    rows, cols = len(grid), len(grid[0])
    uf = UnionFind(rows * cols)

    def index(r, c):
        return r * cols + c

    for r in range(rows):
        for c in range(cols):
            if grid[r][c] == '1':
                # Check right and down neighbors
                if r + 1 < rows and grid[r+1][c] == '1':
                    uf.union(index(r, c), index(r+1, c))
                if c + 1 < cols and grid[r][c+1] == '1':
                    uf.union(index(r, c), index(r, c+1))

    # Count unique roots for '1's
    roots = set()
    for r in range(rows):
        for c in range(cols):
            if grid[r][c] == '1':
                roots.add(uf.find(index(r, c)))
    return len(roots)

# 2) Friend circles
def friend_circles(friends):
    n = len(friends)
    uf = UnionFind(n)
    for i in range(n):
        for j in range(i+1, n):
            if friends[i][j] == 1:
                uf.union(i, j)
    return uf.count()

# 3) Kruskal's MST
def kruskal_mst(edges, n):
    """edges: (weight, u, v)"""
    edges.sort()
    uf = UnionFind(n)
    mst = []
    total_weight = 0

    for weight, u, v in edges:
        if uf.union(u, v):
            mst.append((u, v, weight))
            total_weight += weight
            if len(mst) == n - 1:
                break
    return total_weight, mst

# 4) Detect cycle in undirected graph
def has_cycle(edges, n):
    uf = UnionFind(n)
    for u, v in edges:
        if not uf.union(u, v):
            return True  # Same component → cycle
    return False
```

**Complexities**: Almost O(1) amortized (inverse Ackermann function).

**Segment Tree** for range queries and point updates (O(log n)):

```python
class SegmentTree:
    def __init__(self, data, func=sum):
        """func: query operation (sum, min, max, gcd, etc.)"""
        self.n = len(data)
        self.func = func
        self.size = 1
        while self.size < self.n:
            self.size <<= 1
        self.tree = [0] * (2 * self.size)
        # Build
        for i in range(self.n):
            self.tree[self.size + i] = data[i]
        for i in range(self.size - 1, 0, -1):
            self.tree[i] = self.func(self.tree[2*i], self.tree[2*i + 1])

    def update(self, index, value):
        """Set arr[index] = value"""
        pos = self.size + index
        self.tree[pos] = value
        pos //= 2
        while pos:
            self.tree[pos] = self.func(self.tree[2*pos], self.tree[2*pos + 1])
            pos //= 2

    def query(self, left, right):
        """Query on interval [left, right]"""
        left += self.size
        right += self.size
        res_left = None
        res_right = None

        while left <= right:
            if left % 2 == 1:
                if res_left is None:
                    res_left = self.tree[left]
                else:
                    res_left = self.func(res_left, self.tree[left])
                left += 1
            if right % 2 == 0:
                if res_right is None:
                    res_right = self.tree[right]
                else:
                    res_right = self.func(self.tree[right], res_right)
                right -= 1
            left //= 2
            right //= 2

        if res_left is None:
            return res_right
        if res_right is None:
            return res_left
        return self.func(res_left, res_right)

# Lazy Propagation Segment Tree (range updates)
class LazySegmentTree:
    def __init__(self, data):
        self.n = len(data)
        self.size = 1
        while self.size < self.n:
            self.size <<= 1
        self.tree = [0] * (2 * self.size)
        self.lazy = [0] * (2 * self.size)
        for i in range(self.n):
            self.tree[self.size + i] = data[i]
        for i in range(self.size - 1, 0, -1):
            self.tree[i] = self.tree[2*i] + self.tree[2*i + 1]

    def _push(self, node, left, right):
        if self.lazy[node] != 0:
            self.tree[node] += self.lazy[node] * (right - left + 1)
            if left != right:
                self.lazy[2*node] += self.lazy[node]
                self.lazy[2*node + 1] += self.lazy[node]
            self.lazy[node] = 0

    def range_add(self, ql, qr, value, node=1, left=0, right=None):
        if right is None:
            right = self.size - 1
        self._push(node, left, right)

        if qr < left or right < ql:
            return
        if ql <= left and right <= qr:
            self.lazy[node] += value
            self._push(node, left, right)
            return

        mid = (left + right) // 2
        self.range_add(ql, qr, value, 2*node, left, mid)
        self.range_add(ql, qr, value, 2*node+1, mid+1, right)
        self.tree[node] = self.tree[2*node] + self.tree[2*node + 1]

    def range_sum(self, ql, qr, node=1, left=0, right=None):
        if right is None:
            right = self.size - 1
        self._push(node, left, right)

        if qr < left or right < ql:
            return 0
        if ql <= left and right <= qr:
            return self.tree[node]

        mid = (left + right) // 2
        return (self.range_sum(ql, qr, 2*node, left, mid) +
                self.range_sum(ql, qr, 2*node+1, mid+1, right))

# Usage
arr = [1, 3, 5, 7, 9, 11]
